# Max Of Two

## 问题描述

实现一个函数，输入两个整数 `a` 和 `b`，返回两者中的较大值。

约定：

- 如果 `a >= b`，返回 `a`
- 否则返回 `b`
- 函数不修改任何内存

## 正确代码

```c
int max_of_two(int a, int b) {
    if (a >= b) {
        return a;
    } else {
        return b;
    }
}
```

## 说明

这道题适合验证最基础的分支语义：

- 一个 `if/else`
- 无循环
- 无堆内存
- 后置条件可以写成“返回值等于 `a` 或 `b`，且不小于另一个输入”

#include "../verification_stdlib.h"

int max3(int x, int y, int z)
  /*@ Require
        INT_MIN <= x && x <= INT_MAX &&
        INT_MIN <= y && y <= INT_MAX &&
        INT_MIN <= z && z <= INT_MAX && emp
      Ensure
        __return >= x &&
        __return >= y &&
        __return >= z && emp
   */
{
  if (x < y)
    if (y < z)
      return z;
    else
      return y;
  else
    if (x < z)
      return z;
    else
      return x;
}

#include "../../verification_stdlib.h"

/*@ Extern Coq (factorial: Z -> Z) */

int fac(int n)
/*@ Require
      0 <= n && n <= 10 && emp
    Ensure
      __return == factorial(n@pre) && emp
*/
{
    int i;
    int res = 1;

    for (i = 1; i <= n; ++i) {
        res = res * i;
    }

    return res;
}

#include "../../verification_stdlib.h"

/*@ Extern Coq (climb_stairs_z: Z -> Z) */
/*@ Import Coq Require Import climb_stairs */

int climbStairs(int n)
/*@ Require
      0 <= n && n <= 45 && emp
    Ensure
      __return == climb_stairs_z(n@pre) && emp
*/
{
    if (n <= 1) {
        return 1;
    }

    int prev2 = 1;
    int prev1 = 1;
    int cur = 0;

    for (int i = 2; i <= n; i++) {
        cur = prev1 + prev2;
        prev2 = prev1;
        prev1 = cur;
    }

    return cur;
}

#include "../../verification_stdlib.h"

int max_of_two(int a, int b)
/*@ Require
      INT_MIN <= a && a <= INT_MAX &&
      INT_MIN <= b && b <= INT_MAX && emp
    Ensure
      (__return == a@pre || __return == b@pre) &&
      __return >= a@pre &&
      __return >= b@pre && emp
*/
{
    if (a >= b) {
        return a;
    } else {
        return b;
    }
}
